package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class JoinEngineConfigDefaultsTest {

	private static final String ENABLED_PROPERTY = "rdf4j.optimizer.joinengine.enabled";

	@Test
	void defaultsEnableEngineWhenPropertyUnset() {
		String previous = System.getProperty(ENABLED_PROPERTY);
		try {
			System.clearProperty(ENABLED_PROPERTY);
			JoinEngineConfig defaults = JoinEngineConfig.defaults();
			assertTrue(defaults.isEnabled(), "Expected engine to be enabled by default");
		} finally {
			restoreProperty(previous);
		}
	}

	@Test
	void defaultsRespectExplicitDisableProperty() {
		String previous = System.getProperty(ENABLED_PROPERTY);
		try {
			System.setProperty(ENABLED_PROPERTY, "false");
			JoinEngineConfig defaults = JoinEngineConfig.defaults();
			assertFalse(defaults.isEnabled(), "Expected explicit property disable to be honored");
		} finally {
			restoreProperty(previous);
		}
	}

	private void restoreProperty(String previous) {
		if (previous == null) {
			System.clearProperty(ENABLED_PROPERTY);
		} else {
			System.setProperty(ENABLED_PROPERTY, previous);
		}
	}
}
